export const getFeedbackForAnswer = async (user: User, question: string, userAnswer: string, correctAnswer: string | number) => {
    const ai = getAiClient();
    const isCorrect = userAnswer.trim().toLowerCase() === String(correctAnswer).trim().toLowerCase();

    const prompt = `A grade ${user.grade} student named ${user.name} answered a question.
    Question: "${question}"
    Their answer: "${userAnswer}"
    Correct answer: "${correctAnswer}"
    The student was ${isCorrect ? 'correct' : 'incorrect'}.

    Provide a short, encouraging feedback message. 
    If they were correct, verify specifically what they did right (e.g. "You counted all 5 stars!").
    If they were incorrect, help them understand why. Specifically refer to the numbers or words in the question. For example, "It looks like you might have added instead of subtracted" or "Close! 3 plus 2 makes 5."
    Keep the tone warm, supportive, and appropriate for a grade ${user.grade} child. Limit to 2-3 sentences.`;

    const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash',
        contents: prompt,
    });

    return {
        isCorrect,
        feedbackText: response.text,
    };
};

import React from 'react';
import { VisualMathExercise } from '../types';

interface MathVisualizationProps {
  visualization: VisualMathExercise['visualization'];
  isIncorrect?: boolean;
}

const MathVisualization: React.FC<MathVisualizationProps> = ({ visualization, isIncorrect }) => {
  const { elements, operation } = visualization;

  return (
    <div className={`flex items-center justify-center space-x-4 md:space-x-6 my-6 p-4 rounded-2xl transition-all duration-500 ${isIncorrect ? 'bg-red-50 ring-4 ring-red-200' : 'bg-transparent'}`}>
      {elements.map((element, index) => (
        <React.Fragment key={index}>
          <div className="flex flex-wrap justify-center gap-2">
            {Array.from({ length: element.count }).map((_, i) => (
              <span key={i} className="text-4xl md:text-6xl select-none transition-transform hover:scale-110 cursor-default" role="img" aria-label={element.emoji}>
                {element.emoji}
              </span>
            ))}
          </div>
          {index < elements.length - 1 && (
            <span className={`text-4xl md:text-6xl font-bold transition-colors duration-300 ${isIncorrect ? 'text-red-500 animate-pulse' : 'text-blue-500'}`}>
              {operation}
            </span>
          )}
        </React.Fragment>
      ))}
       <span className={`text-4xl md:text-6xl font-bold transition-colors duration-300 ${isIncorrect ? 'text-red-500' : 'text-slate-500'}`}>= ?</span>
    </div>
  );
};

export default MathVisualization;

import React, { useState, useEffect } from 'react';
import { User, Exercise, Feedback, Subject, MathCategory, EnglishCategory, SessionSummaryData, VisualMathExercise } from '../types';
import { getFeedbackForAnswer } from '../services/geminiService';
import AiFeedback from './AiFeedback';
import MathVisualization from './MathVisualization';

const QUESTIONS_PER_SESSION = 5;

interface TextExerciseViewProps {
  user: User;
  subject: Subject;
  category?: MathCategory | EnglishCategory;
  onBack: () => void;
  onSessionComplete: (summary: SessionSummaryData, newProgress: number) => void;
  exerciseGenerator: (previousCorrectness?: 'correct' | 'incorrect' | 'first') => Promise<Exercise>;
  initialProgress: number;
}

const TextExerciseView: React.FC<TextExerciseViewProps> = ({
  user,
  subject,
  category,
  onBack,
  onSessionComplete,
  exerciseGenerator,
  initialProgress
}) => {
  const [exercise, setExercise] = useState<Exercise | null>(null);
  const [userAnswer, setUserAnswer] = useState('');
  const [feedback, setFeedback] = useState<Feedback | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [questionCount, setQuestionCount] = useState(0);
  const [correctCount, setCorrectCount] = useState(0);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [speakingWordKey, setSpeakingWordKey] = useState<string | null>(null);

  const fetchExercise = async (previousCorrectness?: 'correct' | 'incorrect' | 'first') => {
    setIsLoading(true);
    setError(null);
    setFeedback(null);
    setUserAnswer('');
    try {
      const ex = await exerciseGenerator(previousCorrectness);
      setExercise(ex);
    } catch (err) {
      setError('Oops! We had trouble generating a question. Please try again.');
      console.error(err);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    fetchExercise('first');
  }, [exerciseGenerator]);

  // Clean up speech synthesis on component unmount or when exercise changes
  useEffect(() => {
    return () => {
        if ('speechSynthesis' in window) {
            window.speechSynthesis.cancel();
        }
    };
  }, [exercise]);

  const handleWordClick = (wordText: string, key: string) => {
    if (!('speechSynthesis' in window)) {
        console.warn("Browser does not support text-to-speech.");
        return;
    }

    window.speechSynthesis.cancel(); // Stop any current speech

    const cleanedWord = wordText.trim().replace(/[.,/#!$%^&*;:{}=\-_`~()?]/g, "");
    if (!cleanedWord) return;

    const utterance = new SpeechSynthesisUtterance(cleanedWord);

    utterance.onstart = () => {
        setSpeakingWordKey(key);
    };
    utterance.onend = () => {
        setSpeakingWordKey(null);
    };
    utterance.onerror = (e) => {
        console.error("Speech synthesis error", e);
        setSpeakingWordKey(null);
    };

    window.speechSynthesis.speak(utterance);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!exercise || isSubmitting || !userAnswer.trim()) return;

    // FIX: Add a type guard to ensure the exercise has question and answer properties.
    // This handles the case of `ReadingPracticeExercise` which shouldn't be in this view.
    if (!('question' in exercise) || !('answer' in exercise)) {
      console.error("Invalid exercise for this view:", exercise);
      return;
    }

    setIsSubmitting(true);
    const fb = await getFeedbackForAnswer(user, exercise.question, userAnswer, exercise.answer);
    setFeedback(fb);

    if (fb.isCorrect) {
      setCorrectCount(prev => prev + 1);
    }
    setIsSubmitting(false);
  };

  const handleNextQuestion = () => {
    const wasCorrect = feedback?.isCorrect;
    const nextQuestionNumber = questionCount + 1;
    if (nextQuestionNumber >= QUESTIONS_PER_SESSION) {
      // Session over
      const finalCorrect = correctCount + (wasCorrect && !feedback ? 1 : 0);
      const newProgress = initialProgress + (finalCorrect / QUESTIONS_PER_SESSION) * 20; // 20% progress for a full session
      onSessionComplete({
          correct: finalCorrect,
          incorrect: QUESTIONS_PER_SESSION - finalCorrect,
          subject: subject,
          category: category,
      }, Math.min(100, newProgress));
    } else {
      setQuestionCount(nextQuestionNumber);
      fetchExercise(wasCorrect ? 'correct' : 'incorrect');
    }
  };

  const renderExerciseContent = () => {
    if (!exercise) return null;
    if (subject === 'math' && exercise.type === 'visual') {
        const visualExercise = exercise as VisualMathExercise;
        if (visualExercise.visualization) {
            return <MathVisualization 
                visualization={visualExercise.visualization} 
                isIncorrect={!!feedback && !feedback.isCorrect}
            />;
        }
    }
    return null;
  }

  const renderInput = () => {
    if (!exercise) return null;
    // FIX: Check for 'options' property before accessing it to satisfy TypeScript for the union type 'Exercise'.
    if ('options' in exercise && exercise.options && exercise.options.length > 0) {
      return (
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mt-4">
          {exercise.options.map((option, index) => (
            <button
              key={index}
              type="button"
              onClick={() => {
                if (!feedback) setUserAnswer(String(option));
              }}
              className={`p-4 rounded-lg text-lg transition-colors border-2 ${
                userAnswer === String(option)
                  ? 'bg-blue-500 text-white border-blue-700'
                  : 'bg-white hover:bg-blue-100 border-slate-300'
              } ${feedback ? 'cursor-not-allowed' : ''}`}
              disabled={!!feedback}
            >
              {option}
            </button>
          ))}
        </div>
      );
    }
    return (
       <input
          type={subject === 'math' ? 'number' : 'text'}
          value={userAnswer}
          onChange={(e) => setUserAnswer(e.target.value)}
          className="w-full max-w-md mx-auto p-4 text-2xl border-2 border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 transition-all text-center"
          placeholder="Type your answer here"
          disabled={!!feedback}
        />
    )
  }

  // FIX: Property 'story' does not exist on any exercise type, causing type errors. Only check for 'passage'.
  const storyOrPassage = (exercise && 'passage' in exercise && typeof exercise.passage === 'string') 
    ? exercise.passage 
    : null;

  return (
    <div className="bg-white p-6 md:p-8 rounded-2xl shadow-2xl max-w-4xl mx-auto text-center relative">
       <button 
        onClick={onBack}
        className="absolute top-4 left-4 text-sm text-slate-500 hover:text-blue-600 transition-colors"
      >
        &larr; Back
      </button>

      <div className="mb-4">
        <div className="w-full bg-gray-200 rounded-full h-2.5">
            <div className="bg-blue-600 h-2.5 rounded-full" style={{ width: `${((questionCount) / QUESTIONS_PER_SESSION) * 100}%` }}></div>
        </div>
        <span className="text-sm text-slate-500 mt-1">Question {questionCount + 1} of {QUESTIONS_PER_SESSION}</span>
      </div>


      {isLoading && <div className="p-8 text-lg text-slate-600">Loading your question...</div>}
      {error && <div className="p-8 text-lg text-red-600">{error}</div>}

      {!isLoading && !error && exercise && (
        <form onSubmit={handleSubmit}>
          {storyOrPassage && (
            <div className="text-left text-lg md:text-xl text-slate-700 mb-6 leading-relaxed bg-slate-50 p-4 rounded-lg">
                {storyOrPassage.split(/(\s+)/).map((segment, index) => {
                    const key = `word-${index}`;
                    const isClickable = segment.trim().length > 0;
                    if (isClickable) {
                        return (
                            <span
                                key={key}
                                onClick={() => handleWordClick(segment, key)}
                                className={`cursor-pointer transition-colors rounded p-0.5 -m-0.5 ${speakingWordKey === key ? 'bg-yellow-300' : 'hover:bg-yellow-100'}`}
                            >
                                {segment}
                            </span>
                        );
                    }
                    return <span key={key}>{segment}</span>;
                })}
            </div>
          )}

          {/* FIX: Add a type guard to ensure exercise has a question before rendering it. */}
          {'question' in exercise && (
            <h2 className="text-2xl md:text-3xl font-semibold text-slate-800 mb-6" style={{ whiteSpace: 'pre-wrap' }}>{exercise.question}</h2>
          )}

          {renderExerciseContent()}

          <div className="my-6">
            {renderInput()}
          </div>

          {!feedback && (
             <button 
                type="submit"
                className="w-full max-w-xs mx-auto bg-blue-600 text-white font-bold py-3 px-6 rounded-lg text-xl hover:bg-blue-700 disabled:bg-slate-300 transition-colors"
                disabled={!userAnswer.trim() || isSubmitting}
              >
                {isSubmitting ? 'Checking...' : 'Check Answer'}
              </button>
          )}
        </form>
      )}

      {feedback && (
        <div className="mt-6 flex flex-col items-center gap-4">
            <AiFeedback feedback={feedback} />
            <button
                type="button"
                onClick={handleNextQuestion}
                className="w-full max-w-xs mx-auto bg-green-600 text-white font-bold py-3 px-6 rounded-lg text-xl hover:bg-green-700 transition-colors"
            >
                {questionCount + 1 >= QUESTIONS_PER_SESSION ? 'Finish Session' : 'Next Question'}
            </button>
        </div>
      )}
    </div>
  );
};

export default TextExerciseView;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { User, SessionSummaryData, ReadingPracticeExercise, WordStatus } from '../types';
import { generateEnglishExercise } from '../services/geminiService';
import MicIcon from './icons/MicIcon';

const QUESTIONS_PER_SESSION = 5;

// Web Speech API interfaces
interface SpeechRecognition extends EventTarget {
  continuous: boolean;
  interimResults: boolean;
  lang: string;
  onresult: (event: SpeechRecognitionEvent) => void;
  onend: () => void;
  onerror: (event: SpeechRecognitionErrorEvent) => void;
  start: () => void;
  stop: () => void;
  abort: () => void;
}

interface SpeechRecognitionEvent extends Event {
  results: {
    isFinal: boolean;
    [key: number]: { transcript: string };
    length: number;
  }[];
}

interface SpeechRecognitionErrorEvent extends Event {
    error: string;
    message: string;
}

declare global {
  interface Window {
    SpeechRecognition: new () => SpeechRecognition;
    webkitSpeechRecognition: new () => SpeechRecognition;
  }
}

interface ReadingViewProps {
  user: User;
  initialProgress: number;
  onBack: () => void;
  onSessionComplete: (summary: SessionSummaryData, newProgress: number) => void;
}

const ReadingView: React.FC<ReadingViewProps> = ({ user, initialProgress, onBack, onSessionComplete }) => {
    const [exercise, setExercise] = useState<ReadingPracticeExercise | null>(null);
    const [isLoading, setIsLoading] = useState(true);
    const [error, setError] = useState<string | null>(null);
    const [questionCount, setQuestionCount] = useState(0);
    const [sessionWords, setSessionWords] = useState<{ sentence: string, wpm: number, accuracy: number }[]>([]);

    const [isListening, setIsListening] = useState(false);
    const [wordStatuses, setWordStatuses] = useState<WordStatus[]>([]);
    const [startTime, setStartTime] = useState<number | null>(null);

    const recognitionRef = useRef<SpeechRecognition | null>(null);

    const originalWords = exercise?.sentence.trim().split(/\s+/) || [];

    const fetchExercise = useCallback(async () => {
        setIsLoading(true);
        setError(null);
        setIsListening(false);
        setWordStatuses([]);
        if (recognitionRef.current) {
            recognitionRef.current.abort();
        }

        try {
            const ex = await generateEnglishExercise(user, 'reading_practice', questionCount === 0 ? 'first' : undefined);
            if (ex.type === 'reading_practice') {
                setExercise(ex);
                setWordStatuses(new Array(ex.sentence.trim().split(/\s+/).length).fill('pending'));
            } else {
                throw new Error("Generated wrong exercise type.");
            }
        } catch (err) {
            setError('Oops! We had trouble generating a sentence. Please try again.');
            console.error(err);
        } finally {
            setIsLoading(false);
        }
    }, [user, questionCount]);

    useEffect(() => {
        fetchExercise();
    }, [fetchExercise]);

    // Initialize SpeechRecognition when exercise changes
    useEffect(() => {
        const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
        if (!SpeechRecognition) {
            setError("Sorry, your browser doesn't support speech recognition.");
            return;
        }

        const recognition = new SpeechRecognition();
        recognition.continuous = true;
        recognition.interimResults = true;
        recognition.lang = 'en-US';
        recognitionRef.current = recognition;

        recognition.onresult = (event: SpeechRecognitionEvent) => {
            let fullTranscript = '';
            for (let i = 0; i < event.results.length; ++i) {
                fullTranscript += event.results[i][0].transcript;
            }

            // Normalize speech and target
            const spokenWords = fullTranscript.trim().toLowerCase().split(/\s+/).filter(w => w.length > 0);

            if (!exercise) return;
             const currentOriginalWords = exercise.sentence.trim().split(/\s+/);
             const newStatuses: WordStatus[] = new Array(currentOriginalWords.length).fill('pending');

             currentOriginalWords.forEach((originalWord, index) => {
                const cleanOriginalWord = originalWord.toLowerCase().replace(/[.,/#!$%^&*;:{}=\-_`~()?]/g, "");
                if (index < spokenWords.length) {
                    if (spokenWords[index] === cleanOriginalWord) {
                        newStatuses[index] = 'correct';
                    } else {
                        newStatuses[index] = 'incorrect';
                    }
                }
            });

            setWordStatuses(newStatuses);
        };

        recognition.onend = () => {
             setIsListening(false);
        };

        recognition.onerror = (event) => {
            console.error("Speech recognition error", event.error);
            if (event.error === 'not-allowed') {
                setError("Microphone access denied. Please allow microphone access to use this feature.");
            }
            setIsListening(false);
        };

        return () => {
            recognition.abort();
        };
    }, [exercise]); 

    const handleStartReading = () => {
        if (recognitionRef.current) {
            try {
                // Determine if we are restarting or starting fresh
                setStartTime(Date.now());
                setIsListening(true);
                setWordStatuses(new Array(originalWords.length).fill('pending'));
                recognitionRef.current.start();
            } catch (e) {
                console.error("Failed to start recognition", e);
                // Sometimes it throws if already started, safe to ignore or handle
            }
        }
    };

    const handleStopReading = () => {
        if (recognitionRef.current) {
            recognitionRef.current.stop();
            setIsListening(false);

            const endTime = Date.now();
            const durationInMinutes = (endTime - (startTime || endTime)) / 60000;
            const correctCount = wordStatuses.filter(s => s === 'correct').length;

            // Avoid division by zero and unrealistic numbers for very short durations
            const effectiveDuration = Math.max(durationInMinutes, 0.05); // min 3 seconds
            const wpm = Math.round(correctCount / effectiveDuration);
            const accuracy = originalWords.length > 0 ? Math.round((correctCount / originalWords.length) * 100) : 0;

            setSessionWords(prev => [...prev, { sentence: exercise!.sentence, wpm, accuracy }]);
        }
    };

    const handleNext = () => {
        if (questionCount + 1 >= QUESTIONS_PER_SESSION) {
            // Finish session
            const totalWPM = sessionWords.reduce((acc, s) => acc + s.wpm, 0);
            const totalAccuracy = sessionWords.reduce((acc, s) => acc + s.accuracy, 0);
            const avgWPM = sessionWords.length > 0 ? Math.round(totalWPM / sessionWords.length) : 0;
            const avgAccuracy = sessionWords.length > 0 ? Math.round(totalAccuracy / sessionWords.length) : 0;
            const newProgress = initialProgress + 20; // 20% for a full session

            onSessionComplete({
                correct: avgAccuracy, // Re-using for summary score
                incorrect: 100 - avgAccuracy,
                subject: 'english',
                category: 'reading_practice',
                wpm: avgWPM,
                accuracy: avgAccuracy,
            }, Math.min(100, newProgress));

        } else {
            setQuestionCount(prev => prev + 1);
        }
    }

    const renderSentence = () => {
        if (!exercise) return null;
        return originalWords.map((word, index) => {
            const status = wordStatuses[index];
            let colorClass = 'text-slate-800';
            if (status === 'correct') colorClass = 'text-green-600 font-bold';
            if (status === 'incorrect') colorClass = 'text-red-500 line-through opacity-70';
            // Pending remains default

            return <span key={index} className={`transition-all duration-200 mx-1 ${colorClass}`}>{word}</span>
        });
    }

    const renderButton = () => {
        // Check if we have results for the current sentence (meaning the user finished reading it)
        const currentSentenceResult = sessionWords.length === questionCount + 1;

        if (currentSentenceResult) {
             return (
                <button onClick={handleNext} className="w-full max-w-xs mx-auto bg-green-600 text-white font-bold py-3 px-6 rounded-lg text-xl hover:bg-green-700 transition-colors shadow-lg">
                    {questionCount + 1 >= QUESTIONS_PER_SESSION ? 'Finish Session' : 'Next Sentence'}
                </button>
            );
        }

        if (isListening) {
             return (
                <button onClick={handleStopReading} className="flex items-center justify-center gap-3 w-full max-w-xs mx-auto bg-red-600 text-white font-bold py-3 px-6 rounded-lg text-xl hover:bg-red-700 transition-colors shadow-lg animate-pulse">
                    <span>🛑</span> Stop
                </button>
            );
        }

        return (
            <button onClick={handleStartReading} className="flex items-center justify-center gap-3 w-full max-w-xs mx-auto bg-blue-600 text-white font-bold py-3 px-6 rounded-lg text-xl hover:bg-blue-700 transition-colors shadow-lg">
                <MicIcon /> Start Reading
            </button>
        );
    }

    const results = sessionWords.length === questionCount + 1 ? sessionWords[questionCount] : null;

    return (
        <div className="bg-white p-6 md:p-8 rounded-2xl shadow-2xl max-w-4xl mx-auto text-center relative">
            <button onClick={onBack} className="absolute top-4 left-4 text-sm text-slate-500 hover:text-blue-600 transition-colors">&larr; Back</button>
            <div className="mb-4">
                <div className="w-full bg-gray-200 rounded-full h-2.5">
                    <div className="bg-blue-600 h-2.5 rounded-full" style={{ width: `${(questionCount / QUESTIONS_PER_SESSION) * 100}%` }}></div>
                </div>
                <span className="text-sm text-slate-500 mt-1">Sentence {questionCount + 1} of {QUESTIONS_PER_SESSION}</span>
            </div>

            {isLoading && <div className="p-8 text-lg text-slate-600 animate-pulse">Generating a reading challenge for you...</div>}
            {error && <div className="p-8 text-lg text-red-600 bg-red-50 rounded-lg border border-red-200">{error}</div>}

            {!isLoading && !error && exercise && (
                <>
                    <div className="text-3xl md:text-5xl font-medium text-slate-800 mb-8 p-8 bg-slate-50 rounded-xl min-h-[160px] flex items-center justify-center flex-wrap shadow-inner border border-slate-100">
                        {renderSentence()}
                    </div>

                    {results && (
                        <div className="flex justify-center gap-8 my-6 text-center animate-fade-in bg-slate-50 p-4 rounded-lg">
                             <div>
                                <p className="text-4xl font-bold text-blue-500">{results.wpm}</p>
                                <p className="text-sm text-slate-500 uppercase tracking-wide">WPM</p>
                            </div>
                            <div>
                                <p className="text-4xl font-bold text-green-500">{results.accuracy}%</p>
                                <p className="text-sm text-slate-500 uppercase tracking-wide">Accuracy</p>
                            </div>
                        </div>
                    )}

                    <div className="my-6">
                       {renderButton()}
                    </div>

                    {isListening && (
                        <p className="text-slate-500 italic mt-4">Read the sentence aloud...</p>
                    )}
                </>
            )}
        </div>
    );
};

export default ReadingView;

import { GoogleGenAI, Type } from "@google/genai";
import { User, Subject, MathCategory, EnglishCategory } from '../types';

// Per guidelines, API key must be from process.env.API_KEY
// We will create the client just before the API call to ensure it's fresh.
const getAiClient = () => new GoogleGenAI({ apiKey: process.env.API_KEY! });

const createSystemInstruction = (user: User, subject: Subject, category: string): string => {
    let instruction = `You are a fun and encouraging AI tutor for a grade ${user.grade} student named ${user.name}. 
    Your goal is to create an educational exercise that is engaging and appropriate for their age.
    The subject is ${subject}, focusing on ${category}.
    The response must be a JSON object that strictly follows the schema provided. Do not include any markdown formatting like \`\`\`json or any introductory text.`;

    if (subject === 'english' && category === 'reading_practice') {
        instruction += `

You are also an expert in early childhood reading education, specializing in the "Bob Books" phonics-based methodology. The sentence you generate for reading practice MUST adhere to the following principles:
- **Phonetic Focus:** Use primarily phonetically regular, decodable words.
- **CVC Words:** For early grades (1-2), heavily favor CVC (consonant-vowel-consonant) words (e.g., cat, sun, pin).
- **Repetition:** Use repetition of words and sounds to build confidence.
- **Simple Structure:** The sentence must be grammatically simple and very short.
- **Real Words Only:** Every word must be a valid, correctly-spelled English word. Do not invent words.
- **Gradual Complexity based on grade ${user.grade}:**
  - **Grade 1:** Strictly CVC words and a few basic sight words (e.g., a, the, is, on, see, I). Example: "A big pig sat."
  - **Grade 2:** Introduce consonant blends (e.g., stop, frog), digraphs (e.g., fish, chat), and more common sight words. Example: "The fish swims in the pond."
  - **Grades 3+:** Sentences can be slightly longer and include multi-syllable but still decodable words. The focus remains on pronunciation practice, not complex narrative. Example: "The children started to finish their project."`;
    }

    return instruction;
}

const createUserPrompt = (previousCorrectness?: 'correct' | 'incorrect' | 'first'): string => {
    let prompt = "Generate a new exercise.";
    if (previousCorrectness === 'correct') {
        prompt += ` The student just answered the previous question correctly, so make this one a little more challenging, but still within their grade level and adhering to all system instructions.`;
    } else if (previousCorrectness === 'incorrect') {
        prompt += ` The student struggled with the last question, so generate a slightly easier one to help them build confidence.`;
    } else {
        prompt += ` This is the first question of the session.`;
    }
    return prompt;
}

const mathExerciseSchema = {
    type: Type.OBJECT,
    properties: {
        type: { type: Type.STRING, description: 'Either "visual" for grades 1-2 or "text" for grades 3-6.'},
        question: { type: Type.STRING },
        answer: { type: Type.NUMBER },
        visualization: {
            type: Type.OBJECT,
            description: 'Required if type is "visual", otherwise omit. Use simple, common emojis.',
            properties: {
                elements: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            emoji: { type: Type.STRING },
                            count: { type: Type.NUMBER }
                        },
                        required: ['emoji', 'count']
                    }
                },
                operation: { type: Type.STRING, description: 'e.g., "+", "-", "×", "÷"' }
            },
            required: ['elements', 'operation']
        }
    },
    required: ['type', 'question', 'answer']
};

export const generateMathExercise = async (user: User, category: MathCategory, previousCorrectness?: 'correct' | 'incorrect' | 'first') => {
  const ai = getAiClient();
  const systemInstruction = createSystemInstruction(user, 'math', category);
  const userPrompt = createUserPrompt(previousCorrectness);

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash',
    contents: userPrompt,
    config: {
        systemInstruction,
        responseMimeType: "application/json",
        responseSchema: mathExerciseSchema,
    },
  });

  const jsonText = response.text.trim();
  try {
    return JSON.parse(jsonText);
  } catch (e) {
    console.error("Failed to parse JSON from Gemini:", jsonText, e);
    throw new Error("Could not generate a valid exercise.");
  }
};

