};

const hebrewExerciseSchema = {
    type: Type.OBJECT,
    properties: {
        type: { type: Type.STRING, description: 'Always "text" for Hebrew.' },
        question: { type: Type.STRING, description: 'Question in Hebrew, with vowels (nikkud) for clarity.' },
        options: {
            type: Type.ARRAY,
            items: { type: Type.STRING, description: 'Options in Hebrew with vowels.' }
        },
        answer: { type: Type.STRING, description: 'The correct answer in Hebrew.' }
    },
    required: ['type', 'question', 'answer']
};

export const generateHebrewExercise = async (user: User, previousCorrectness?: 'correct' | 'incorrect' | 'first') => {
  const ai = getAiClient();
  const systemInstruction = createSystemInstruction(user, 'hebrew', 'reading and basic vocabulary');
  const userPrompt = createUserPrompt(previousCorrectness);

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash',
    contents: userPrompt,
    config: {
        systemInstruction,
        responseMimeType: "application/json",
        responseSchema: hebrewExerciseSchema,
    },
  });

  const jsonText = response.text.trim();
  try {
    return JSON.parse(jsonText);
  } catch (e) {
    console.error("Failed to parse JSON from Gemini:", jsonText, e);
    throw new Error("Could not generate a valid exercise.");
  }
};

export const getFeedbackForAnswer = async (user: User, question: string, userAnswer: string, correctAnswer: string | number) => {
    const ai = getAiClient();
    const isCorrect = userAnswer.trim().toLowerCase() === String(correctAnswer).trim().toLowerCase();

    const prompt = `A grade ${user.grade} student named ${user.name} answered a question.
    Question: "${question}"
    Their answer: "${userAnswer}"
    Correct answer: "${correctAnswer}"
    The student was ${isCorrect ? 'correct' : 'incorrect'}.

    Provide a short, encouraging feedback message. 
    If they were correct, verify specifically what they did right (e.g. "You counted all 5 stars!").
    If they were incorrect, help them understand why. Specifically refer to the numbers or words in the question. For example, "It looks like you might have added instead of subtracted" or "Close! 3 plus 2 makes 5."
    Keep the tone warm, supportive, and appropriate for a grade ${user.grade} child. Limit to 2-3 sentences.`;

    const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash',
        contents: prompt,
    });

    return {
        isCorrect,
        feedbackText: response.text,
    };
};

import React from 'react';
import { VisualMathExercise } from '../types';

interface MathVisualizationProps {
  visualization: VisualMathExercise['visualization'];
  isIncorrect?: boolean;
}

const MathVisualization: React.FC<MathVisualizationProps> = ({ visualization, isIncorrect }) => {
  const { elements, operation } = visualization;

  return (
    <div className={`flex items-center justify-center space-x-4 md:space-x-6 my-6 p-4 rounded-2xl transition-all duration-500 ${isIncorrect ? 'bg-red-50 ring-4 ring-red-200' : 'bg-transparent'}`}>
      {elements.map((element, index) => (
        <React.Fragment key={index}>
          <div className="flex flex-wrap justify-center gap-2">
            {Array.from({ length: element.count }).map((_, i) => (
              <span key={i} className="text-4xl md:text-6xl select-none transition-transform hover:scale-110 cursor-default" role="img" aria-label={element.emoji}>
                {element.emoji}
              </span>
            ))}
          </div>
